package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class ReflectionAccessFilterHelperTest {

  @Test
  void testIsAnyPlatformType_withAndroidType() throws Exception {
    // Use reflection to mock isAndroidType(String)
    var methodIsAndroidType = ReflectionAccessFilterHelper.class.getDeclaredMethod("isAndroidType", String.class);
    methodIsAndroidType.setAccessible(true);

    // Android class name example
    Class<?> androidClass = Class.forName("android.app.Activity");
    // It should return true because isAndroidType(androidClass.getName()) returns true
    // But we can't mock static private method easily without a framework like PowerMock
    // So test with a known android class name that starts with "android."
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(androidClass));
  }

  @Test
  void testIsAnyPlatformType_withKotlinType() throws Exception {
    // Use reflection to get kotlin.Unit class to avoid compile error
    Class<?> kotlinClass;
    try {
      kotlinClass = Class.forName("kotlin.Unit");
    } catch (ClassNotFoundException e) {
      // If kotlin.Unit class is not available in classpath, skip test
      return;
    }
    // kotlin.Unit name starts with "kotlin."
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(kotlinClass));
  }

  @Test
  void testIsAnyPlatformType_withKotlinxType() {
    // We can't create a class with name starting with kotlinx., so test false case here for coverage:
    assertFalse(ReflectionAccessFilterHelper.isAnyPlatformType(Object.class));
  }

  @Test
  void testIsAnyPlatformType_withScalaType() throws Exception {
    // Create a dummy class with name starting with scala.
    // Since we can't create such a class, test with a proxy class name via reflection
    Class<?> scalaClass;
    try {
      scalaClass = Class.forName("scala.collection.Seq$");
    } catch (ClassNotFoundException e) {
      // If scala class not available, skip test
      return;
    }
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(scalaClass));
  }

  @Test
  void testIsAnyPlatformType_withNonPlatformType() {
    assertFalse(ReflectionAccessFilterHelper.isAnyPlatformType(String.class));
  }
}
